import{_ as t,o as s,c as a,ag as i}from"./chunks/framework.f-eIl1f0.js";const u=JSON.parse('{"title":"Design Philosophy","description":"","frontmatter":{},"headers":[],"relativePath":"guide/design-philosophy.md","filePath":"guide/design-philosophy.md"}'),o={name:"guide/design-philosophy.md"};function r(n,e,l,h,c,p){return s(),a("div",null,[...e[0]||(e[0]=[i(`<h1 id="design-philosophy" tabindex="-1">Design Philosophy <a class="header-anchor" href="#design-philosophy" aria-label="Permalink to &quot;Design Philosophy&quot;">​</a></h1><h2 id="why-22-colors" tabindex="-1">Why 22 Colors? <a class="header-anchor" href="#why-22-colors" aria-label="Permalink to &quot;Why 22 Colors?&quot;">​</a></h2><p>The 22-color terminal format (16 ANSI + 6 special) is the <strong>universal pivot format</strong>. Every modern terminal emulator -- Ghostty, Kitty, Alacritty, iTerm2, WezTerm -- already defines exactly these 22 colors. By using this as the palette layer, swatch gets natural interoperability with every terminal theme ecosystem (Base16, Catppuccin, iTerm2 exports, Ghostty configs) without lossy translation.</p><p>The 16 ANSI colors cover the full accent spectrum (red, green, yellow, blue, magenta, cyan + bright variants), and the 6 special colors (foreground, background, cursor, cursor-text, selection, selection-text) define the essential chrome. This is enough to derive a rich UI theme, and nothing is wasted.</p><h2 id="why-separate-palette-from-theme" tabindex="-1">Why Separate Palette from Theme? <a class="header-anchor" href="#why-separate-palette-from-theme" aria-label="Permalink to &quot;Why Separate Palette from Theme?&quot;">​</a></h2><p>The two-layer split serves two audiences:</p><ul><li><strong>Theme authors</strong> work with ColorPalette -- concrete terminal colors they can see and tune</li><li><strong>UI developers</strong> work with Theme -- 33 semantic tokens like <code>$primary</code>, <code>$error</code>, <code>$surface</code> that describe purpose, not appearance</li></ul><p><code>deriveTheme()</code> is the bridge. It applies consistent rules: warm primaries pair with cool selection colors, chrome inverts for dark/light, focus borders are always blue (accessibility convention). Theme authors never need to think about these rules -- they pick colors they like, and <code>deriveTheme()</code> handles the semantic mapping.</p><h2 id="why-not-just-hsl-manipulation" tabindex="-1">Why Not Just HSL Manipulation? <a class="header-anchor" href="#why-not-just-hsl-manipulation" aria-label="Permalink to &quot;Why Not Just HSL Manipulation?&quot;">​</a></h2><p>Some theme systems generate everything from a single hue. This produces technically harmonious but visually bland themes. Real themes like Nord, Catppuccin, and Dracula have carefully hand-picked accent colors that don&#39;t follow simple hue rotations.</p><p>swatch respects this: the palette stores <strong>actual colors</strong> from the theme author. The builder API can generate colors via hue rotation when you want convenience, but built-in themes use hand-tuned values from their original sources.</p><h2 id="why-built-in-themes" tabindex="-1">Why Built-in Themes? <a class="header-anchor" href="#why-built-in-themes" aria-label="Permalink to &quot;Why Built-in Themes?&quot;">​</a></h2><p>Rather than depending on an external theme registry, swatch ships 43 palettes from 15 theme families. Benefits:</p><ul><li>Zero network requests</li><li>Guaranteed to work (validated at build time)</li><li>Consistent ColorPalette mapping</li><li>Instant access via <code>presetTheme(&quot;name&quot;)</code></li></ul><p>For themes not included, use <code>importBase16()</code> to bring in any Base16 scheme, or define a <code>ColorPalette</code> directly.</p><h2 id="token-resolution" tabindex="-1">Token Resolution <a class="header-anchor" href="#token-resolution" aria-label="Permalink to &quot;Token Resolution&quot;">​</a></h2><p>The <code>$</code> prefix convention (<code>$primary</code>, <code>$bg</code>, <code>$error</code>) lets you mix semantic tokens with literal colors in the same API:</p><div class="language-typescript vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">typescript</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">resolveThemeColor</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;$primary&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, theme) </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// looks up theme.primary</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">resolveThemeColor</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;#FF0000&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, theme) </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// passes through unchanged</span></span></code></pre></div><p>This makes token resolution a no-op for literal colors, keeping the API simple for components that accept both tokens and raw hex values.</p><h2 id="design-influences" tabindex="-1">Design Influences <a class="header-anchor" href="#design-influences" aria-label="Permalink to &quot;Design Influences&quot;">​</a></h2><p>swatch&#39;s architecture was informed by studying TUI frameworks (Textual, BubbleTea/Lipgloss), desktop/web design systems (Apple HIG, M3), terminal theme ecosystems (Catppuccin, Base16, Omarchy), and TUI tools with strong theming (oh-my-pi, Zed).</p><p>Key insights from this research:</p><ol><li><strong>Every mature theme system uses two layers</strong>: raw palette -&gt; semantic mapping</li><li><strong>Terminal emulators expose 16 ANSI + 6 special colors</strong> -- the universal baseline</li><li><strong>OKLCH</strong> is the right color space for derivation (perceptually uniform, unlike RGB/HSL)</li><li><strong>One color in, full theme out</strong> is essential for onboarding (adopted from Textual)</li><li><strong>49 tokens is the sweet spot</strong> -- 33 semantic tokens + 16 palette colors provide enough for rich TUIs while remaining easy to maintain</li></ol><p>See <a href="./comparisons.html">Inspirations</a> for detailed notes on each system.</p>`,24)])])}const m=t(o,[["render",r]]);export{u as __pageData,m as default};
